// ============================================
// AGENTE TÉCNICO v2.0 - DATOS COMPLETOS
// ============================================
// MEJORAS:
// 1. Incluye 5 velas recientes con OHLCV
// 2. SMAs múltiples (9, 20, 50, 200)
// 3. ATR real para volatilidad
// 4. Fortaleza de divisas del par
// 5. Patrones de velas detectados
// ============================================

const context = $input.all()[0].json;
const marketData = context.market_data || {};

// ============================================
// EXTRAER DATOS DEL SÍMBOLO CORRECTO
// ============================================
const symbol = marketData.best_pair || "EURUSD";
const isJPY = symbol.includes("JPY");
const decimals = isJPY ? 1000 : 100000;
const pipMultiplier = isJPY ? 100 : 10000;

// Precio correcto del símbolo
const currentPrice = marketData.technical?.current_price || 
    marketData.all_prices?.[symbol] || 0;

// ============================================
// DATOS DE VELAS
// ============================================
const recentCandles = marketData.technical?.candles_recent || [];

// Calcular SMAs si hay suficientes velas
let sma9 = 0, sma20 = 0, sma50 = 0, sma200 = 0;
if (recentCandles.length >= 9) {
    sma9 = recentCandles.slice(-9).reduce((s, c) => s + (c.close || 0), 0) / 9;
}
if (recentCandles.length >= 20) {
    sma20 = recentCandles.slice(-20).reduce((s, c) => s + (c.close || 0), 0) / 20;
}
if (recentCandles.length >= 50) {
    sma50 = recentCandles.slice(-50).reduce((s, c) => s + (c.close || 0), 0) / 50;
}
// SMA200 solo si hay suficientes (puede venir de data fetcher)
if (recentCandles.length >= 200) {
    sma200 = recentCandles.slice(-200).reduce((s, c) => s + (c.close || 0), 0) / 200;
}

// ============================================
// CALCULAR ATR (Average True Range)
// ============================================
let atr = 0;
if (recentCandles.length >= 14) {
    let trueRanges = [];
    for (let i = 1; i < Math.min(15, recentCandles.length); i++) {
        const prev = recentCandles[i - 1];
        const curr = recentCandles[i];
        const high = curr.high || 0;
        const low = curr.low || 0;
        const prevClose = prev.close || 0;
        const trueRange = Math.max(
            high - low,
            Math.abs(high - prevClose),
            Math.abs(low - prevClose)
        );
        trueRanges.push(trueRange);
    }
    atr = trueRanges.reduce((s, tr) => s + tr, 0) / trueRanges.length;
} else {
    // Default ATR si no hay suficientes velas
    atr = currentPrice * (isJPY ? 0.003 : 0.0003);
}

// ============================================
// DETECTAR PATRONES DE VELAS
// ============================================
let candlePattern = "none";
if (recentCandles.length >= 2) {
    const last = recentCandles[recentCandles.length - 1];
    const prev = recentCandles[recentCandles.length - 2];

    const lastBody = Math.abs((last.close || 0) - (last.open || 0));
    const lastRange = (last.high || 0) - (last.low || 0);
    const prevBody = Math.abs((prev.close || 0) - (prev.open || 0));

    const lastIsBullish = (last.close || 0) > (last.open || 0);
    const prevIsBullish = (prev.close || 0) > (prev.open || 0);

    // Doji
    if (lastRange > 0 && lastBody / lastRange < 0.1) {
        candlePattern = "doji";
    }
    // Hammer (bullish reversal)
    else if (lastRange > 0) {
        const lowerWick = Math.min(last.close || 0, last.open || 0) - (last.low || 0);
        const upperWick = (last.high || 0) - Math.max(last.close || 0, last.open || 0);
        if (lowerWick > lastBody * 2 && upperWick < lastBody) {
            candlePattern = lastIsBullish ? "hammer_bullish" : "hammer_bearish";
        }
        // Engulfing
        else if (lastBody > prevBody * 1.5 && lastIsBullish !== prevIsBullish) {
            candlePattern = lastIsBullish ? "bullish_engulfing" : "bearish_engulfing";
        }
    }
}

// ============================================
// VOLUMEN RELATIVO
// ============================================
let currentVolume = 0;
let avgVolume = 0;
let volumeRatio = 1;
if (recentCandles.length >= 5) {
    currentVolume = recentCandles[recentCandles.length - 1]?.tick_volume || 0;
    avgVolume = recentCandles.slice(-20).reduce((s, c) => s + (c.tick_volume || 0), 0) / Math.min(20, recentCandles.length);
    volumeRatio = avgVolume > 0 ? currentVolume / avgVolume : 1;
}

// ============================================
// INDICADORES TÉCNICOS
// ============================================
const rsi = marketData.technical?.rsi || 50;
const rsiStatus = rsi < 30 ? "oversold" : (rsi > 70 ? "overbought" : "neutral");
const trend = marketData.technical?.trend || "neutral";
const support = marketData.technical?.support || (currentPrice * 0.995);
const resistance = marketData.technical?.resistance || (currentPrice * 1.005);
const score = marketData.best_score || 50;

// Posición del precio vs SMAs
let priceVsSma9 = "neutral";
let priceVsSma20 = "neutral";
let priceVsSma50 = "neutral";

if (currentPrice > 0) {
    if (sma9 > 0) priceVsSma9 = currentPrice > sma9 * 1.001 ? "above" : (currentPrice < sma9 * 0.999 ? "below" : "at");
    if (sma20 > 0) priceVsSma20 = currentPrice > sma20 * 1.001 ? "above" : (currentPrice < sma20 * 0.999 ? "below" : "at");
    if (sma50 > 0) priceVsSma50 = currentPrice > sma50 * 1.001 ? "above" : (currentPrice < sma50 * 0.999 ? "below" : "at");
}

// ============================================
// FORTALEZA DE DIVISAS
// ============================================
const currencyStrength = marketData.currency_strength || {};
const baseCurrency = symbol.substring(0, 3);
const quoteCurrency = symbol.substring(3, 6);
const baseStrength = currencyStrength.strength?.[baseCurrency] || "neutral";
const quoteStrength = currencyStrength.strength?.[quoteCurrency] || "neutral";

// ============================================
// EXPOSICIÓN ACTUAL
// ============================================
const positions = marketData.positions?.details || [];
const symbolPositions = positions.filter(p => p.symbol === symbol);
const totalExposure = symbolPositions.reduce((sum, p) => sum + Math.abs(p.volume || 0), 0);

// ============================================
// CONSTRUIR PROMPT COMPLETO
// ============================================
const last5Candles = recentCandles.slice(-5).map((c, i) => {
    const isBullish = (c.close || 0) > (c.open || 0);
    return `Candle${i+1}: O:${c.open || 0} H:${c.high || 0} L:${c.low || 0} C:${c.close || 0} V:${c.tick_volume || 0} ${isBullish ? "BULL" : "BEAR"}`;
}).join(" | ");

const prompt = `[INST] You are an expert forex trading analyst. Analyze ${symbol} with FULL technical data.

═══════════════════════════════════════
📊 TECHNICAL DATA FOR ${symbol}
═══════════════════════════════════════
Current Price: ${currentPrice.toFixed(decimals === 1000 ? 3 : 5)}
RSI (14): ${rsi} (${rsiStatus.toUpperCase()})
Trend: ${trend.toUpperCase()} | Technical Score: ${score}/100

═══ MOVING AVERAGES ═══
SMA 9: ${sma9.toFixed(decimals === 1000 ? 3 : 5)} | Price: ${priceVsSma9.toUpperCase()}
SMA 20: ${sma20.toFixed(decimals === 1000 ? 3 : 5)} | Price: ${priceVsSma20.toUpperCase()}
SMA 50: ${sma50.toFixed(decimals === 1000 ? 3 : 5)} | Price: ${priceVsSma50.toUpperCase()}

═══ SUPPORT/RESISTANCE ═══
Support: ${support.toFixed(decimals === 1000 ? 3 : 5)}
Resistance: ${resistance.toFixed(decimals === 1000 ? 3 : 5)}

═══ VOLATILITY ═══
ATR (14): ${atr.toFixed(decimals === 1000 ? 3 : 5)} (${(atr / currentPrice * 100).toFixed(3)}%)

═══ VOLUME ═══
Current Volume: ${currentVolume}
Avg Volume (20): ${avgVolume.toFixed(0)}
Volume Ratio: ${volumeRatio.toFixed(2)}x ${volumeRatio > 1.5 ? "(HIGH)" : "(NORMAL)"}

═══ CANDLESTICK PATTERNS ═══
Detected Pattern: ${candlePattern.toUpperCase()}
Last 5 Candles: ${last5Candles}

═══ CURRENCY STRENGTH ═══
${baseCurrency}: ${baseStrength.toUpperCase()}
${quoteCurrency}: ${quoteStrength.toUpperCase()}
${baseStrength === "bullish" && quoteStrength === "bearish" ? "→ STRONG BULLISH setup for " + symbol : ""}${baseStrength === "bearish" && quoteStrength === "bullish" ? "→ STRONG BEARISH setup for " + symbol : ""}

═══ CURRENT EXPOSURE ═══
Open Positions in ${symbol}: ${symbolPositions.length}
Total Exposure: ${totalExposure.toFixed(2)} lots

═══════════════════════════════════════
📋 REQUIRED JSON OUTPUT:
═══════════════════════════════════════
Return ONLY valid JSON:
{
  "signal": "buy" or "sell" or "neutral",
  "confidence": 0-100 (integer),
  "analysis": "Brief technical reasoning (1 sentence)",
  "structure": "bullish" or "bearish" or "range",
  "momentum": "strong" or "moderate" or "weak",
  "entry_zone": [low, high] (within ±0.2% of ${currentPrice}),
  "stop_zone": [low, high] (within 0.3-0.5% of ${currentPrice})
}

⚠️ CRITICAL: entry_zone MUST be within ±${(currentPrice * 0.002).toFixed(decimals === 1000 ? 2 : 5)} of ${currentPrice}
⚠️ Use EXACT price ${currentPrice} as reference for all calculations [/INST]`;

console.log(`📈 Agente Técnico v2.0 - ${symbol}`);
console.log(`   Price: ${currentPrice} | RSI: ${rsi} | Trend: ${trend}`);
console.log(`   Pattern: ${candlePattern} | Volume: ${volumeRatio.toFixed(2)}x`);
console.log(`   Prompt length: ${prompt.length} chars`);

return [{
    json: {
        agent: "technical",
        context: context,
        technical_data: {
            symbol: symbol,
            price: currentPrice,
            rsi: rsi,
            trend: trend,
            support: support,
            resistance: resistance,
            score: score,
            sma9: sma9,
            sma20: sma20,
            sma50: sma50,
            atr: atr,
            volume_ratio: volumeRatio,
            candle_pattern: candlePattern,
            base_strength: baseStrength,
            quote_strength: quoteStrength,
            current_exposure: totalExposure
        },
        prompt: prompt,
        status: "ready"
    }
}];

// ============================================
// AGENTE FUNDAMENTAL v2.0 - DATOS COMPLETOS
// ============================================
// MEJORAS:
// 1. Titulares reales de noticias
// 2. Sentimiento por noticia
// 3. Eventos del calendario con forecast
// 4. Sesgo neto calculado
// 5. Riesgo de volatilidad por eventos
// ============================================

const context = $input.all()[0].json;
const marketData = context.market_data || {};

// ============================================
// EXTRAER DATOS DEL SÍMBOLO CORRECTO
// ============================================
const symbol = marketData.best_pair || "EURUSD";
const baseCurrency = symbol.substring(0, 3);
const quoteCurrency = symbol.substring(3, 6);

// Datos fundamentales del símbolo
const fundamentalData = marketData.fundamental || {};
const newsList = fundamentalData.relevant_news || [];
const calendarList = fundamentalData.calendar_events || [];

// ============================================
// PROCESAR NOTICIAS
// ============================================
let bullishNews = 0;
let bearishNews = 0;
let neutralNews = 0;
let highImpactNews = [];
let newsHeadlines = [];

for (const news of newsList) {
    const sentiment = news.sentiment?.toLowerCase() || "neutral";
    const impact = news.impact?.toLowerCase() || news.relevance?.toLowerCase() || "medium";

    if (sentiment === "bullish") bullishNews++;
    else if (sentiment === "bearish") bearishNews++;
    else neutralNews++;

    if (impact === "high" || news.impact === "high") {
        highImpactNews.push({
            headline: news.headline || news.title || "Unknown",
            sentiment: sentiment,
            currency: news.currency || ""
        });
    }

    newsHeadlines.push(`[${sentiment.toUpperCase()}] ${news.headline || news.title || "No headline"}`);
}

const netBias = bullishNews - bearishNews;
const totalNews = newsList.length;

// ============================================
// PROCESAR EVENTOS DEL CALENDARIO
// ============================================
let highImpactEvents = [];
let eventDetails = [];

for (const event of calendarList) {
    const impact = event.impact?.toLowerCase() || "medium";
    eventDetails.push({
        event: event.event || event.name || "Unknown",
        currency: event.currency || "",
        impact: impact,
        forecast: event.forecast || event.expected || "N/A",
        time: event.time || event.date || "N/A"
    });

    if (impact === "high") {
        highImpactEvents.push(event.event || event.name || "Unknown");
    }
}

const netEventBias = eventDetails.filter(e => 
    e.impact === "high" && e.currency === baseCurrency
).length - eventDetails.filter(e => 
    e.impact === "high" && e.currency === quoteCurrency
).length;

// ============================================
// EVALUAR RIESGO FUNDAMENTAL
// ============================================
let fundamentalRisk = "low";
let marketBias = "neutral";

if (highImpactEvents.length > 2 || highImpactNews.length > 3) {
    fundamentalRisk = "high";
} else if (highImpactEvents.length > 0 || highImpactNews.length > 0) {
    fundamentalRisk = "medium";
}

if (netBias > 2) marketBias = "strongly_bullish";
else if (netBias > 0) marketBias = "bullish";
else if (netBias < -2) marketBias = "strongly_bearish";
else if (netBias < 0) marketBias = "bearish";

// Ajustar por eventos
if (highImpactEvents.length > 0 && netEventBias < 0) {
    marketBias = marketBias.includes("bullish") ? "neutral" : "bearish";
}

// ============================================
// CONSTRUIR PROMPT COMPLETO
// ============================================
const newsSummary = newsHeadlines.slice(0, 5).join("\n") || "No news available";
const eventsSummary = eventDetails.map(e => 
    `[${e.impact.toUpperCase()}] ${e.currency}: ${e.event} (Forecast: ${e.forecast})`
).join("\n") || "No events scheduled";

const prompt = `[INST] You are an expert forex fundamental analyst. Evaluate ${symbol} based on news and economic events.

═══════════════════════════════════════
📰 FUNDAMENTAL DATA FOR ${symbol}
═══════════════════════════════════════
Base Currency: ${baseCurrency}
Quote Currency: ${quoteCurrency}

═══ NEWS SENTIMENT ═══
Total News: ${totalNews}
Bullish: ${bullishNews} | Bearish: ${bearishNews} | Neutral: ${neutralNews}
Net Bias: ${netBias > 0 ? "+" : ""}${netBias} ${netBias > 0 ? "BULLISH" : (netBias < 0 ? "BEARISH" : "NEUTRAL")}

═══ NEWS HEADLINES ═══
${newsSummary}

═══ HIGH IMPACT NEWS ═══
${highImpactNews.length > 0 ? highImpactNews.map(n => `[${n.sentiment.toUpperCase()}] ${n.headline}`).join("\n") : "None"}

═══ ECONOMIC CALENDAR ═══
${eventsSummary}

═══ HIGH IMPACT EVENTS ═══
${highImpactEvents.length > 0 ? highImpactEvents.join(", ") : "None scheduled"}

═══ RISK ASSESSMENT ═══
Fundamental Risk: ${fundamentalRisk.toUpperCase()}
Market Bias: ${marketBias.toUpperCase()}
${fundamentalRisk === "high" ? "⚠️ HIGH VOLATILITY EXPECTED - Consider waiting" : ""}

═══════════════════════════════════════
📋 REQUIRED JSON OUTPUT:
═══════════════════════════════════════
Return ONLY valid JSON:
{
  "recommendation": "act" or "wait" or "avoid",
  "confidence": 0-100 (integer),
  "analysis": "Brief fundamental reasoning (1 sentence)",
  "impact_direction": "bullish" or "bearish" or "neutral" or "volatile",
  "sentiment_score": -100 to 100 (integer, negative=bearish),
  "news_risk": "low" or "medium" or "high"
}

⚠️ "act" = conditions favorable for trading
⚠️ "wait" = uncertain conditions, wait for clarity
⚠️ "avoid" = high risk events, do NOT trade [/INST]`;

console.log(`📰 Agente Fundamental v2.0 - ${symbol}`);
console.log(`   News: ${totalNews} (B:${bullishNews} Be:${bearishNews}) | Events: ${eventDetails.length}`);
console.log(`   Net Bias: ${netBias} | Risk: ${fundamentalRisk}`);
console.log(`   Prompt length: ${prompt.length} chars`);

return [{
    json: {
        agent: "fundamental",
        context: context,
        fundamental_data: {
            symbol: symbol,
            total_news: totalNews,
            bullish_news: bullishNews,
            bearish_news: bearishNews,
            net_bias: netBias,
            high_impact_news: highImpactNews.length,
            high_impact_events: highImpactEvents.length,
            fundamental_risk: fundamentalRisk,
            market_bias: marketBias
        },
        prompt: prompt,
        status: "ready"
    }
}];

// ============================================
// AGENTE SENTIMIENTO v2.0 - DATOS COMPLETOS
// ============================================
// MEJORAS:
// 1. Posiciones abiertas detalladas
// 2. Órdenes pendientes por dirección
// 3. Ratio long/short combinado
// 4. Señal contraria por posicionamiento extremo
// 5. Contexto risk-on/risk-off
// ============================================

const context = $input.all()[0].json;
const marketData = context.market_data || {};

// ============================================
// EXTRAER DATOS DEL SÍMBOLO CORRECTO
// ============================================
const symbol = marketData.best_pair || "EURUSD";

// Posiciones abiertas
const positions = marketData.positions?.details || [];
const symbolPositions = positions.filter(p => p.symbol === symbol);

// Órdenes pendientes
const pendingOrders = marketData.pending_orders?.details || [];
const symbolPendings = pendingOrders.filter(p => p.symbol === symbol);

// ============================================
// CALCULAR VOLÚMENES POR DIRECCIÓN
// ============================================
let longVolume = 0;
let shortVolume = 0;
let longCount = 0;
let shortCount = 0;

for (const p of symbolPositions) {
    const v = Math.abs(p.volume || 0);
    const type = (p.type || "").toLowerCase();

    if (type === "buy" || type === "long") {
        longVolume += v;
        longCount++;
    } else if (type === "sell" || type === "short") {
        shortVolume += v;
        shortCount++;
    }
}

let pendingLongVolume = 0;
let pendingShortVolume = 0;
let pendingLongCount = 0;
let pendingShortCount = 0;

for (const p of symbolPendings) {
    const v = Math.abs(p.volume || 0);
    const type = (p.type || "").toLowerCase();

    if (type.includes("buy") || type === "long") {
        pendingLongVolume += v;
        pendingLongCount++;
    } else if (type.includes("sell") || type === "short") {
        pendingShortVolume += v;
        pendingShortCount++;
    }
}

// ============================================
// CALCULAR RATIOS
// ============================================
const totalLong = longVolume + pendingLongVolume;
const totalShort = shortVolume + pendingShortVolume;
const totalVolume = totalLong + totalShort;

let longShortRatio = 0;
let sentimentScore = 0;

if (totalVolume > 0) {
    longShortRatio = totalLong / (totalShort || 0.001);
    sentimentScore = ((totalLong - totalShort) / totalVolume) * 100;
}

// ============================================
// DETERMINAR NIVEL DE SENTIMIENTO
// ============================================
let sentimentLevel = "neutral";
let contrarianSignal = "none";

if (sentimentScore > 70) {
    sentimentLevel = "extreme_bullish";
    contrarianSignal = "sell"; // Contrarian: too many longs
} else if (sentimentScore > 30) {
    sentimentLevel = "bullish";
} else if (sentimentScore < -70) {
    sentimentLevel = "extreme_bearish";
    contrarianSignal = "buy"; // Contrarian: too many shorts
} else if (sentimentScore < -30) {
    sentimentLevel = "bearish";
}

// ============================================
// ANÁLISIS DE POSICIONAMIENTO
// ============================================
let positioningAnalysis = "balanced";

if (longCount > shortCount * 2 && longCount > 0) {
    positioningAnalysis = "crowded_long";
} else if (shortCount > longCount * 2 && shortCount > 0) {
    positioningAnalysis = "crowded_short";
} else if (totalVolume === 0) {
    positioningAnalysis = "no_positions";
}

// ============================================
// FORTALEZA DE DIVISAS PARA CONTEXTO
// ============================================
const currencyStrength = marketData.currency_strength || {};
const sentiment = currencyStrength.sentiment || {};
const marketMood = sentiment.market_mood || sentiment.overall || "neutral";
const baseCurrency = symbol.substring(0, 3);
const quoteCurrency = symbol.substring(3, 6);
const baseStrength = currencyStrength.strength?.[baseCurrency] || "neutral";
const quoteStrength = currencyStrength.strength?.[quoteCurrency] || "neutral";

// ============================================
// CONSTRUIR PROMPT COMPLETO
// ============================================
const prompt = `[INST] You are an expert forex sentiment analyst. Analyze market positioning for ${symbol}.

═══════════════════════════════════════
💭 SENTIMENT DATA FOR ${symbol}
═══════════════════════════════════════

═══ OPEN POSITIONS ═══
Long Positions: ${longCount} (${longVolume.toFixed(2)} lots)
Short Positions: ${shortCount} (${shortVolume.toFixed(2)} lots)

═══ PENDING ORDERS ═══
Pending Buy: ${pendingLongCount} (${pendingLongVolume.toFixed(2)} lots)
Pending Sell: ${pendingShortCount} (${pendingShortVolume.toFixed(2)} lots)

═══ COMBINED ANALYSIS ═══
Total Long: ${totalLong.toFixed(2)} lots
Total Short: ${totalShort.toFixed(2)} lots
Long/Short Ratio: ${longShortRatio.toFixed(2)}:1
Sentiment Score: ${sentimentScore.toFixed(0)} (range: -100 to +100, positive=bullish)

═══ SENTIMENT LEVEL ═══
Current Level: ${sentimentLevel.toUpperCase()}
Contrarian Signal: ${contrarianSignal.toUpperCase()}
Positioning: ${positioningAnalysis.toUpperCase()}

═══ MARKET CONTEXT ═══
Market Mood: ${marketMood.toUpperCase()}
${baseCurrency} Strength: ${baseStrength.toUpperCase()}
${quoteCurrency} Strength: ${quoteStrength.toUpperCase()}
${sentimentLevel.includes("extreme") ? "⚠️ EXTREME positioning - contrarian opportunity" : ""}

═══ INTERPRETATION GUIDE ═══
- Score > +70: Extreme bullish → Contrarian SELL signal
- Score > +30: Moderate bullish → Bias long
- Score -30 to +30: Neutral → No bias
- Score < -30: Moderate bearish → Bias short  
- Score < -70: Extreme bearish → Contrarian BUY signal

═══════════════════════════════════════
📋 REQUIRED JSON OUTPUT:
═══════════════════════════════════════
Return ONLY valid JSON:
{
  "sentiment": "bullish" or "bearish" or "neutral",
  "confidence": 0-100 (integer),
  "analysis": "Brief sentiment reasoning (1 sentence)",
  "contrary_signal": "buy" or "sell" or "none",
  "sentiment_score": -100 to 100 (integer)
}

⚠️ If sentiment is EXTREME, use contrary_signal for the opposite direction
⚠️ Consider market mood and currency strength in your analysis [/INST]`;

console.log(`💭 Agente Sentimiento v2.0 - ${symbol}`);
console.log(`   Long: ${totalLong.toFixed(2)} | Short: ${totalShort.toFixed(2)} | Ratio: ${longShortRatio.toFixed(2)}:1`);
console.log(`   Score: ${sentimentScore} | Level: ${sentimentLevel} | Contrarian: ${contrarianSignal}`);
console.log(`   Prompt length: ${prompt.length} chars`);

return [{
    json: {
        agent: "sentiment",
        context: context,
        sentiment_data: {
            symbol: symbol,
            long_volume: totalLong,
            short_volume: totalShort,
            long_short_ratio: longShortRatio,
            sentiment_score: sentimentScore,
            sentiment_level: sentimentLevel,
            contrarian_signal: contrarianSignal,
            positioning: positioningAnalysis,
            market_mood: marketMood
        },
        prompt: prompt,
        status: "ready"
    }
}];

// ============================================
// AGENTE ESTADÍSTICO v2.0 - DATOS COMPLETOS
// ============================================
// MEJORAS:
// 1. Winrate histórico por agente
// 2. Sharpe ratio estimado
// 3. Drawdown máximo reciente
// 4. Ajuste de volumen por performance
// 5. Probabilidad bayesiana actualizada
// ============================================

const context = $input.all()[0].json;
const marketData = context.market_data || {};
const memory = context.memory || {};

// ============================================
// EXTRAER DATOS DEL SÍMBOLO CORRECTO
// ============================================
const symbol = marketData.best_pair || "EURUSD";
const isJPY = symbol.includes("JPY");
const currentPrice = marketData.technical?.current_price || marketData.all_prices?.[symbol] || 0;
const rsi = marketData.technical?.rsi || 50;
const trend = marketData.technical?.trend || "neutral";
const score = marketData.best_score || 50;

// ============================================
// MÉTRICAS DE RENDIMIENTO
// ============================================
const globalMetrics = memory.global_metrics || {};
const agentPerformance = memory.performance || {};
const preferences = memory.preferences || {};

const totalTrades = globalMetrics.total_trades || 0;
const winningTrades = globalMetrics.winning_trades || 0;
const losingTrades = globalMetrics.losing_trades || 0;
const globalWinrate = totalTrades > 0 ? (winningTrades / totalTrades * 100) : 50;

// Winrates por agente
const techPerf = agentPerformance.technical || {};
const fundPerf = agentPerformance.fundamental || {};
const sentPerf = agentPerformance.sentiment || {};
const statPerf = agentPerformance.statistical || {};

const techWinrate = techPerf.winrate || (techPerf.total > 0 ? (techPerf.wins / techPerf.total * 100) : 50);
const fundWinrate = fundPerf.winrate || (fundPerf.total > 0 ? (fundPerf.wins / fundPerf.total * 100) : 50);
const sentWinrate = sentPerf.winrate || (sentPerf.total > 0 ? (sentPerf.wins / sentPerf.total * 100) : 50);
const statWinrate = statPerf.winrate || (statPerf.total > 0 ? (statPerf.wins / statPerf.total * 100) : 50);

// ============================================
// CALCULAR SHARPE RATIO ESTIMADO
// ============================================
// Sharpe = (Avg Return - Risk Free) / Std Dev of Returns
// Simplified: assuming avg win = +50 pips, avg loss = -30 pips
const avgWin = 50; // pips
const avgLoss = 30; // pips
const expectedReturn = (globalWinrate / 100 * avgWin) - ((100 - globalWinrate) / 100 * avgLoss);
const volatility = avgWin * 0.5; // rough estimate
const sharpeRatio = volatility > 0 ? (expectedReturn / volatility) : 0;

// ============================================
// CALCULAR DRAWDOWN ESTIMADO
// ============================================
// Assuming max drawdown is ~3x the avg loss streak
const maxDrawdown = avgLoss * 3; // rough estimate in pips

// ============================================
// AJUSTE DE VOLUMEN POR PERFORMANCE
// ============================================
let volumeAdjustment = 1.0;

if (totalTrades >= 10) {
    if (globalWinrate > 60) {
        volumeAdjustment = 1.2; // Increase volume if profitable
    } else if (globalWinrate < 40) {
        volumeAdjustment = 0.5; // Decrease volume if losing
    } else if (globalWinrate < 45) {
        volumeAdjustment = 0.7;
    }
}

// ============================================
// PROBABILIDAD BAYESIANA
// ============================================
// P(Success | Evidence) = P(Evidence | Success) * P(Success) / P(Evidence)
// Simplified: combine winrate + trend strength + RSI position

const trendStrength = trend === "bullish" ? 0.6 : (trend === "bearish" ? 0.4 : 0.5);
const rsiFactor = rsi < 30 ? 0.7 : (rsi > 70 ? 0.3 : 0.5 + (50 - rsi) / 100);
const baseProbability = (globalWinrate / 100);

// Bayesian update
const bayesianProbability = (
    (baseProbability * 0.4) + 
    (trendStrength * 0.3) + 
    (rsiFactor * 0.3)
) * 100;

// ============================================
// RIESGO ESTADÍSTICO
// ============================================
let riskScore = 50; // 0-100, higher = riskier

// Adjust based on winrate
if (globalWinrate < 40) riskScore += 20;
else if (globalWinrate < 45) riskScore += 10;
else if (globalWinrate > 60) riskScore -= 10;

// Adjust based on Sharpe
if (sharpeRatio < 0.5) riskScore += 15;
else if (sharpeRatio > 1.5) riskScore -= 10;

// Adjust based on recent performance
const recentTrades = memory.trades || [];
const last5Trades = recentTrades.slice(-5);
const last5Wins = last5Trades.filter(t => t.result === "win").length;
if (last5Trades.length >= 3) {
    if (last5Wins === 0) riskScore += 20; // Losing streak
    else if (last5Wins >= 4) riskScore -= 10; // Winning streak
}

riskScore = Math.max(0, Math.min(100, riskScore));

// ============================================
// CONSTRUIR PROMPT COMPLETO
// ============================================
const prompt = `[INST] You are an expert statistical analyst. Evaluate trading system performance for ${symbol}.

═══════════════════════════════════════
📊 STATISTICAL DATA FOR ${symbol}
═══════════════════════════════════════

═══ GLOBAL PERFORMANCE ═══
Total Trades: ${totalTrades}
Wins: ${winningTrades} | Losses: ${losingTrades}
Win Rate: ${globalWinrate.toFixed(1)}%
Expected Return: ${expectedReturn.toFixed(1)} pips/trade
Sharpe Ratio: ${sharpeRatio.toFixed(2)}
Max Drawdown (est): ~${maxDrawdown} pips

═══ AGENT WINRATES ═══
Technical Agent: ${techWinrate.toFixed(1)}% (${techPerf.total || 0} trades)
Fundamental Agent: ${fundWinrate.toFixed(1)}% (${fundPerf.total || 0} trades)
Sentiment Agent: ${sentWinrate.toFixed(1)}% (${sentPerf.total || 0} trades)
Statistical Agent: ${statWinrate.toFixed(1)}% (${statPerf.total || 0} trades)

═══ CURRENT INDICATORS ═══
RSI (14): ${rsi}
Trend: ${trend}
Technical Score: ${score}/100
Bayesian Probability: ${bayesianProbability.toFixed(1)}%

═══ RISK METRICS ═══
Risk Score: ${riskScore}/100 (${riskScore > 60 ? "HIGH" : (riskScore < 40 ? "LOW" : "MEDIUM")})
Volume Adjustment: ${volumeAdjustment.toFixed(2)}x
${riskScore > 60 ? "⚠️ HIGH RISK - Consider reducing position size" : ""}

═══ RECENT PERFORMANCE ═══
Last 5 Trades: ${last5Wins}/${last5Trades.length} wins
${last5Wins === 0 && last5Trades.length >= 3 ? "⚠️ LOSING STREAK - Be cautious" : ""}
${last5Wins >= 4 ? "✅ WINNING STREAK - Momentum favorable" : ""}

═══════════════════════════════════════
📋 REQUIRED JSON OUTPUT:
═══════════════════════════════════════
Return ONLY valid JSON:
{
  "volatility": "low" or "normal" or "high",
  "volume_adjustment": 0.5 to 1.5 (float),
  "probability": 0-100 (integer, likelihood of success),
  "confidence": 0-100 (integer)
}

⚠️ probability = your estimated chance of successful trade
⚠️ volume_adjustment = multiplier for position size (1.0 = normal)
⚠️ Consider winrate, Sharpe, and recent streak in your assessment [/INST]`;

