// ============================================
// AGENTE ESTRATEGA v2.0 - FUSIÓN INTELIGENTE
// ============================================
// MEJORAS:
// 1. Score ponderado por weights Y winrates
// 2. Validación R/R mínimo 1.5:1
// 3. Validación precio vs símbolo
// 4. Cálculo de volumen basado en riesgo real
// 5. Fallback seguro si algún agente falla
// ============================================

const allAgents = $input.all();

// ============================================
// INICIALIZAR CON VALORES POR DEFECTO
// ============================================
let technical = { s: "neutral", c: 0 };
let fundamental = { r: "wait", c: 0, d: "neutral" };
let sentiment = { s: "neutral", c: 0, cs: "none" };
let statistical = { c: 0, vol_adj: 1.0, prob: 50 };
let marketData = {};
let agentWeights = { t: 0.35, f: 0.25, se: 0.25, st: 0.15 };
let agentWinrates = { t: 50, f: 50, se: 50, st: 50 };

// ============================================
// EXTRAER DATOS DE AGENTES
// ============================================
for (const item of allAgents) {
    const data = item.json;
    const a = data.analysis;

    if (data.agent === "technical" && a) {
        technical = { 
            s: a.señal || a.signal || "neutral", 
            c: typeof a.confianza === 'number' ? a.confianza : 0 
        };
    }
    if (data.agent === "fundamental" && a) {
        fundamental = { 
            r: a.recomendacion || a.recommendation || "wait", 
            c: typeof a.confianza === 'number' ? a.confianza : 0,
            d: a.direccion_impacto || a.impact_direction || "neutral" 
        };
    }
    if (data.agent === "sentiment" && a) {
        sentiment = { 
            s: a.sentimiento || a.sentiment || "neutral", 
            c: typeof a.confianza === 'number' ? a.confianza : 0,
            cs: a.señal_contraria || a.contrary_signal || "none" 
        };
    }
    if (data.agent === "statistical" && a) {
        statistical = { 
            c: typeof a.confianza === 'number' ? a.confianza : 0,
            vol_adj: typeof a.ajuste_volumen === 'number' ? a.ajuste_volumen : 1.0,
            prob: typeof a.probabilidad_continuacion === 'number' ? a.probabilidad_continuacion : 50
        };
    }
    if (data.context) {
        marketData = data.context.market_data || {};
        if (data.context.memory?.agent_weights) {
            agentWeights = data.context.memory.agent_weights;
        }
        if (data.context.memory?.performance) {
            const perf = data.context.memory.performance;
            agentWinrates = {
                t: perf.technical?.winrate || 50,
                f: perf.fundamental?.winrate || 50,
                se: perf.sentiment?.winrate || 50,
                st: perf.statistical?.winrate || 50
            };
        }
    }
}

// ============================================
// OBTENER DATOS DEL SÍMBOLO
// ============================================
const symbol = marketData.best_pair || "EURUSD";
const isJPY = symbol.includes("JPY");
const price = marketData.technical?.current_price || marketData.all_prices?.[symbol] || 0;
const accountBalance = marketData.risk?.account_balance || 100000;

// Validar precio
const VALID_RANGES = {
    EURUSD: { min: 1.05, max: 1.20 },
    GBPUSD: { min: 1.25, max: 1.40 },
    USDJPY: { min: 140.0, max: 170.0 },
    USDCHF: { min: 0.85, max: 1.00 }
};
const DEFAULT_PRICES = {
    EURUSD: 1.1689, GBPUSD: 1.3570, USDJPY: 159.88, USDCHF: 0.7996
};

let validPrice = price;
const range = VALID_RANGES[symbol];
if (range && (price < range.min || price > range.max)) {
    console.log(`⚠️ Precio ${price} fuera de rango para ${symbol}, usando default`);
    validPrice = DEFAULT_PRICES[symbol];
}
if (validPrice === 0) {
    validPrice = DEFAULT_PRICES[symbol];
}

// ============================================
// CALCULAR SCORE PONDERADO
// ============================================
// Weight each agent by their weight AND their winrate
const tWeight = (agentWeights.t || 0.35) * (agentWinrates.t / 100);
const fWeight = (agentWeights.f || 0.25) * (agentWinrates.f / 100);
const seWeight = (agentWeights.se || 0.25) * (agentWinrates.se / 100);
const stWeight = (agentWeights.st || 0.15) * (agentWinrates.st / 100);

const totalWeight = tWeight + fWeight + seWeight + stWeight;

const tScore = (technical.c / 100) * tWeight;
const fScore = (fundamental.c / 100) * fWeight;
const seScore = (sentiment.c / 100) * seWeight;
const stScore = (statistical.c / 100) * stWeight;

const rawTotalScore = (tScore + fScore + seScore + stScore);
const finalScore = totalWeight > 0 ? (rawTotalScore / totalWeight) * 100 : 0;
const normalizedScore = isNaN(finalScore) ? 0 : Math.min(100, Math.max(0, finalScore));

// ============================================
// CONTAR SEÑALES
// ============================================
let buy = 0, sell = 0;

if (technical.s === "buy") buy++;
if (technical.s === "sell") sell++;

if (fundamental.r === "act" && fundamental.d === "bullish") buy++;
if (fundamental.r === "act" && fundamental.d === "bearish") sell++;
if (fundamental.r === "avoid") { buy = 0; sell = 0; } // Fundamental says avoid

if (sentiment.cs === "buy") buy++;
if (sentiment.cs === "sell") sell++;

// Sentiment alignment check
if (sentiment.s === "bullish" && technical.s === "buy") buy += 0.5; // Bonus for alignment
if (sentiment.s === "bearish" && technical.s === "sell") sell += 0.5;

// ============================================
// DECISIÓN FINAL
// ============================================
const minConfidence = marketData.preferences?.min_confidence || 45;

let decision = "hold";
let decisionReason = "";

// Fundamental says avoid
if (fundamental.r === "avoid") {
    decision = "hold";
    decisionReason = "Fundamental analysis recommends avoiding - high risk events";
}
// Check for buy conditions
else if (normalizedScore >= minConfidence && buy > sell && buy >= 1.5) {
    decision = "buy";
    decisionReason = `Technical: ${technical.s}(${technical.c}%), Fundamental: ${fundamental.r}(${fundamental.d}), Score: ${normalizedScore.toFixed(0)}%`;
}
// Check for sell conditions
else if (normalizedScore >= minConfidence && sell > buy && sell >= 1.5) {
    decision = "sell";
    decisionReason = `Technical: ${technical.s}(${technical.c}%), Fundamental: ${fundamental.r}(${fundamental.d}), Score: ${normalizedScore.toFixed(0)}%`;
}
// Hold
else {
    decision = "hold";
    decisionReason = `Score ${normalizedScore.toFixed(0)}% < ${minConfidence}% OR signals not aligned (B:${buy.toFixed(1)} S:${sell.toFixed(1)})`;
}

// ============================================
// CÁLCULO DE VOLUMEN SEGURO
// ============================================
const riskPercent = 0.02; // 2% risk per trade
const maxRiskAmount = accountBalance * riskPercent;

// Stop distance in pips
const stopPips = isJPY ? 30 : 30; // 30 pips
const pipValue = isJPY ? 1000 : 10; // pip value per standard lot

// Volume calculation: Volume = RiskAmount / (StopPips * PipValue)
const calculatedVolume = maxRiskAmount / (stopPips * pipValue);

// Apply statistical volume adjustment
const baseVolume = calculatedVolume * statistical.vol_adj;

// Apply constraints (MAX 0.05 lots)
const MAX_VOLUME = 0.05;
const MIN_VOLUME = 0.01;

let volume = Math.min(baseVolume, MAX_VOLUME);
volume = Math.max(volume, MIN_VOLUME);
volume = Math.round(volume * 100) / 100;

const actualRisk = volume * stopPips * pipValue;
const riskPercentOfAccount = (actualRisk / accountBalance * 100);

console.log(`💰 Volumen: ${volume} lotes | Riesgo: $${actualRisk.toFixed(2)} (${riskPercentOfAccount.toFixed(2)}%)`);
console.log(`   Base calc: ${calculatedVolume.toFixed(3)} | Stat adj: ${statistical.vol_adj.toFixed(2)}x | Final: ${volume}`);

// ============================================
// NIVELES DE STOP LOSS Y TAKE PROFIT
// ============================================
const slPips = isJPY ? 30 : 0.0030;
const tp1Pips = isJPY ? 45 : 0.0045; // 1.5:1 R/R
const tp2Pips = isJPY ? 60 : 0.0060; // 2:1 R/R

let sl = 0, tp1 = 0, tp2 = 0;

if (decision === "buy") {
    sl = validPrice - slPips;
    tp1 = validPrice + tp1Pips;
    tp2 = validPrice + tp2Pips;
} else if (decision === "sell") {
    sl = validPrice + slPips;
    tp1 = validPrice - tp1Pips;
    tp2 = validPrice - tp2Pips;
}

// Validate R/R ratio
const risk = Math.abs(validPrice - sl);
const reward = Math.abs(tp1 - validPrice);
const rrRatio = risk > 0 ? reward / risk : 0;

if (rrRatio < 1.5 && decision !== "hold") {
    console.log(`⚠️ R/R ${rrRatio.toFixed(2)} < 1.5, adjusting TP1`);
    tp1 = decision === "buy" ? validPrice + (risk * 1.5) : validPrice - (risk * 1.5);
}

// Redondear
const decimals = isJPY ? 1000 : 100000;
sl = sl > 0 ? Math.round(sl * decimals) / decimals : 0;
tp1 = tp1 > 0 ? Math.round(tp1 * decimals) / decimals : 0;
tp2 = tp2 > 0 ? Math.round(tp2 * decimals) / decimals : 0;

// ============================================
// RESUMEN DE AGENTES
// ============================================
const agentsSummary = {
    technical: { signal: technical.s, confidence: technical.c, weight: agentWeights.t, winrate: agentWinrates.t },
    fundamental: { recommendation: fundamental.r, confidence: fundamental.c, direction: fundamental.d, weight: agentWeights.f, winrate: agentWinrates.f },
    sentiment: { sentiment: sentiment.s, confidence: sentiment.c, contrary: sentiment.cs, weight: agentWeights.se, winrate: agentWinrates.se },
    statistical: { confidence: statistical.c, volume_adj: statistical.vol_adj, probability: statistical.prob, weight: agentWeights.st, winrate: agentWinrates.st }
};

// ============================================
// PROMPT PARA MODELO (VALIDACIÓN FINAL)
// ============================================
const prompt = `[INST] You are a senior trading supervisor. Review and validate a trading decision.

═══════════════════════════════════════
DECISION TO VALIDATE
═══════════════════════════════════════
Symbol: ${symbol}
Proposed Decision: ${decision.toUpperCase()}
Confidence Score: ${normalizedScore.toFixed(0)}%
Entry Price: ${validPrice.toFixed(decimals === 1000 ? 3 : 5)}
Stop Loss: ${sl.toFixed(decimals === 1000 ? 3 : 5)}
Take Profit 1: ${tp1.toFixed(decimals === 1000 ? 3 : 5)}
Take Profit 2: ${tp2.toFixed(decimals === 1000 ? 3 : 5)}
Volume: ${volume} lots
Risk: $${actualRisk.toFixed(2)} (${riskPercentOfAccount.toFixed(2)}% of $${accountBalance})
R/R Ratio: ${rrRatio.toFixed(2)}:1

═══ AGENT SIGNALS ═══
Technical: ${technical.s} (${technical.c}%) | Weight: ${(agentWeights.t*100).toFixed(0)}% | WR: ${agentWinrates.t.toFixed(0)}%
Fundamental: ${fundamental.r} ${fundamental.d} (${fundamental.c}%) | Weight: ${(agentWeights.f*100).toFixed(0)}% | WR: ${agentWinrates.f.toFixed(0)}%
Sentiment: ${sentiment.s} contrary:${sentiment.cs} (${sentiment.c}%) | Weight: ${(agentWeights.se*100).toFixed(0)}% | WR: ${agentWinrates.se.toFixed(0)}%
Statistical: ${statistical.prob.toFixed(0)}% prob, vol_adj: ${statistical.vol_adj.toFixed(2)}x | Weight: ${(agentWeights.st*100).toFixed(0)}% | WR: ${agentWinrates.st.toFixed(0)}%

Buy Signals: ${buy.toFixed(1)} | Sell Signals: ${sell.toFixed(1)}

═══════════════════════════════════════
TASK: Validate or override this decision.
Return JSON:
{
  "decision": "${decision}" or "hold" (if you disagree),
  "confidence": 0-100,
  "reasoning": "Why you agree/disagree",
  "entry_price": ${validPrice},
  "stop_loss": ${sl},
  "take_profit": ${tp1},
  "volume": ${volume}
}

⚠️ If R/R < 1.5 or risk > 3%, change to hold
⚠️ Price MUST be ${validPrice} ± 0.2% [/INST]`;

console.log(`🎯 Decisión: ${decision.toUpperCase()} ${symbol}`);
console.log(`   Score: ${normalizedScore.toFixed(0)}% | B:${buy.toFixed(1)} S:${sell.toFixed(1)}`);
console.log(`   Entry: ${validPrice} | SL: ${sl} | TP1: ${tp1} | R/R: ${rrRatio.toFixed(2)}:1`);
console.log(`   Volumen: ${volume} | Riesgo: $${actualRisk.toFixed(2)}`);

return [{
